mapper.select:
SELECT v.id, v.plate_number as plateNumber, v.appointment_id as appointmentId, v.violation_type as violationType, v.custom_type as customType, v.location, v.description, v.appointment_time as appointmentTime, v.enter_time as enterTime, v.leave_time as leaveTime, v.status, CASE WHEN v.status = 'pending' THEN '待处理' WHEN v.status = 'processing' THEN '处理中' WHEN v.status = 'completed' THEN '已处理' WHEN v.status = 'cancelled' THEN '已取消' END as statusText, v.severity, v.photos, v.voice_memo as voiceMemo, v.remark, v.should_blacklist as shouldBlacklist, v.blacklist_reason as blacklistReason, v.created_at as createdAt, -- 业主信息（优先预约记录，其次本地车主，最后月票车主） COALESCE(apt.ownername, o.ownername, mt.user_name) as ownerName, COALESCE(apt.ownerphone, o.ownerphone, mt.user_phone) as ownerPhone, CASE WHEN apt.id IS NOT NULL THEN CONCAT(apt.community, apt.building, '栋', apt.units, '单元', apt.room, '室') WHEN o.id IS NOT NULL THEN CONCAT(o.building, '栋', o.units, '单元', o.roomnumber, '室') WHEN mt.id IS NOT NULL THEN CONCAT(mt.park_name, '停车场月票车主') ELSE NULL END as ownerAddress, o.credit_score as creditScore, -- 业主类型标识 CASE WHEN apt.id IS NOT NULL THEN 'appointment' WHEN o.id IS NOT NULL THEN 'local' WHEN mt.id IS NOT NULL THEN 'monthly' ELSE 'unknown' END as ownerType, -- 月票信息（仅月票车主有） mt.ticket_name as monthTicketName, mt.park_name as parkName, mt.valid_status as monthTicketStatus, -- 🆕 预约详细信息（仅预约车有） apt.visitreason as appointmentReason, apt.appointtype as appointmentType, apt.auditusername as auditorName, apt.auditstatus as appointmentStatus, apt.visitdate as appointmentDate, apt.auditdate as auditDate, CASE WHEN LENGTH(v.plate_number) = 8 THEN true ELSE false END as isNewEnergy FROM violations v LEFT JOIN ownerinfo o ON v.owner_id = o.id LEFT JOIN month_tick mt ON v.month_ticket_id = mt.id LEFT JOIN appointment apt ON v.appointment_id = apt.id
AND v.plate_number LIKE CONCAT('%', #{plateNumber}, '%')
AND v.status = #{status}
AND v.violation_type = #{violationType}
AND v.created_at >= #{startDate}
AND v.created_at <= #{endDate}
AND v.created_by = #{createdByFilter}
AND ( -- 预约车辆：匹配预约表中的community字段 (apt.id IS NOT NULL AND apt.community = #{communityFilter}) OR -- 本地车主：匹配ownerinfo表中的community字段（如果有的话） (o.id IS NOT NULL AND o.community = #{communityFilter}) OR -- 月票车主：匹配month_tick表中的park_name字段 (mt.id IS NOT NULL AND mt.park_name = #{communityFilter}) OR -- 月票车主：匹配month_tick表中的park_name字段 (v.id IS NOT NULL AND v.park_name = #{communityFilter}) )
ORDER BY v.created_at DESC

SELECT v.id, v.plate_number as plateNumber, v.appointment_id as appointmentId, v.violation_type as violationType, v.custom_type as customType, v.location, v.description, v.appointment_time as appointmentTime, v.enter_time as enterTime, v.leave_time as leaveTime, v.status, CASE WHEN v.status = 'pending' THEN '待处理' WHEN v.status = 'processing' THEN '处理中' WHEN v.status = 'completed' THEN '已处理' WHEN v.status = 'cancelled' THEN '已取消' END as statusText, v.severity, v.photos, v.voice_memo as voiceMemo, v.remark, v.should_blacklist as shouldBlacklist, v.blacklist_reason as blacklistReason, v.created_at as createdAt, v.created_by as createdBy, -- 🎓 直接使用violations表中的业主信息字段 v.owner_name as ownerName, v.owner_phone as ownerPhone, v.owner_category as ownerCategory, v.park_name as parkName, -- 业主类型标识（根据is_monthly_ticket字段判断） CASE WHEN v.is_monthly_ticket = 1 THEN 'monthly' WHEN v.owner_category = '业主' THEN 'local' ELSE 'visitor' END as ownerType, -- 从violations表直接读取的字段 v.vip_type_name as monthTicketName, v.owner_address as ownerAddress, v.customer_company as customerCompany, v.customer_room_number as customerRoomNumber, -- 默认空值字段（保持与关联查询返回结构一致） NULL as creditScore, NULL as monthTicketStatus, NULL as appointmentReason, NULL as appointmentType, NULL as auditorName, NULL as appointmentStatus, NULL as appointmentDate, NULL as auditDate, CASE WHEN LENGTH(v.plate_number) = 8 THEN true ELSE false END as isNewEnergy FROM violations v
AND v.plate_number LIKE CONCAT('%', #{plateNumber}, '%')
AND v.status = #{status}
AND v.violation_type = #{violationType}
AND v.created_at >= #{startDate}
AND v.created_at <= #{endDate}
AND v.created_by = #{createdByFilter}
AND v.park_name = #{communityFilter}
ORDER BY v.created_at DESC

SELECT v.plate_number as plateNumber, COUNT(*) as count, -- 业主信息（优先预约记录，其次本地车主，最后月票车主） COALESCE(apt.ownername, o.ownername, mt.user_name) as ownerName, COALESCE(apt.ownerphone, o.ownerphone, mt.user_phone) as phone, CASE WHEN apt.id IS NOT NULL THEN CONCAT(apt.community, apt.building, '栋', apt.units, '单元', apt.room, '室') WHEN o.id IS NOT NULL THEN CONCAT(o.building, '栋', o.units, '单元', o.roomnumber, '室') WHEN mt.id IS NOT NULL THEN CONCAT(mt.park_name, '停车场月票车主') ELSE '未知地址' END as address, o.credit_score as creditScore, -- 业主类型标识 CASE WHEN apt.id IS NOT NULL THEN 'appointment' WHEN o.id IS NOT NULL THEN 'local' WHEN mt.id IS NOT NULL THEN 'monthly' ELSE 'unknown' END as ownerType, -- 月票信息 mt.ticket_name as monthTicketName, mt.park_name as parkName, -- 🆕 预约详细信息（仅预约车有） apt.visitreason as appointmentReason, apt.appointtype as appointmentType, apt.auditusername as auditorName, apt.auditstatus as appointmentStatus, apt.visitdate as appointmentDate, apt.auditdate as auditDate, CASE WHEN LENGTH(v.plate_number) = 8 THEN true ELSE false END as isNewEnergy, GROUP_CONCAT(DISTINCT v.violation_type) as violationTypes, MAX(v.created_at) as lastViolationTime FROM violations v LEFT JOIN ownerinfo o ON v.owner_id = o.id LEFT JOIN month_tick mt ON v.month_ticket_id = mt.id LEFT JOIN appointment apt ON v.appointment_id = apt.id
AND v.created_at >= #{startDate}
AND v.created_at <= #{endDate}
GROUP BY v.plate_number HAVING count >= 2 ORDER BY count DESC, lastViolationTime DESC
LIMIT #{limit}

SELECT v.plate_number as plateNumber, COUNT(*) as count, -- 🎓 直接使用violations表中的业主信息字段 MAX(v.owner_name) as ownerName, MAX(v.owner_phone) as phone, MAX(COALESCE(v.owner_address, '未知地址')) as address, -- 业主类型标识（根据is_monthly_ticket字段判断） CASE WHEN v.is_monthly_ticket = 1 THEN 'monthly' WHEN v.is_monthly_ticket = '0' THEN 'local' ELSE 'visitor' END as ownerType, -- 从violations表直接读取的字段 MAX(v.vip_type_name) as monthTicketName, MAX(v.park_name) as parkName, MAX(v.customer_company) as customerCompany, -- 默认空值字段（保持与关联查询返回结构一致） NULL as creditScore, NULL as appointmentReason, NULL as appointmentType, NULL as auditorName, NULL as appointmentStatus, NULL as appointmentDate, NULL as auditDate, CASE WHEN LENGTH(v.plate_number) = 8 THEN true ELSE false END as isNewEnergy, GROUP_CONCAT(DISTINCT v.violation_type) as violationTypes, MAX(v.created_at) as lastViolationTime FROM violations v
AND v.created_at >= #{startDate}
AND v.created_at <= #{endDate}
AND v.created_by = #{createdByFilter}
AND v.park_name = #{communityFilter}
GROUP BY v.plate_number HAVING count >= 2 ORDER BY count DESC, lastViolationTime DESC
LIMIT #{limit}

SELECT 
    v.status,
    COUNT(*) as count
FROM violations v


        AND v.created_at >= #{startDate}


        AND v.created_at <= #{endDate}


        AND v.plate_number = #{plateNumber}


GROUP BY v.status

SELECT 
    v.status,
    COUNT(*) as count
FROM violations v


        AND v.created_at >= #{startDate}


        AND v.created_at <= #{endDate}


        AND v.plate_number = #{plateNumber}


        AND v.created_by = #{createdByFilter}



        AND v.park_name = #{communityFilter}


GROUP BY v.status

mapper.update:
UPDATE ownerinfo 
SET credit_score = GREATEST(0, credit_score - #{deduction})
WHERE id = #{ownerId}

mapper.select:
SELECT 
    DATE(v.created_at) as date,
    COUNT(*) as count
FROM violations v


        AND v.created_at >= #{startDate}


        AND v.created_at <= #{endDate}


        AND v.plate_number = #{plateNumber}


GROUP BY DATE(v.created_at)
ORDER BY date

SELECT 
    DATE(v.created_at) as date,
    COUNT(*) as count
FROM violations v


        AND v.created_at >= #{startDate}


        AND v.created_at <= #{endDate}


        AND v.plate_number = #{plateNumber}


        AND v.created_by = #{createdByFilter}



        AND v.park_name = #{communityFilter}


GROUP BY DATE(v.created_at)
ORDER BY date

SELECT v.violation_type as violationType, COUNT(*) as count FROM violations v
AND v.created_at >= #{startDate}
AND v.created_at <= #{endDate}
GROUP BY v.violation_type ORDER BY count DESC

SELECT 
    v.violation_type as violationType,
    COUNT(*) as count
FROM violations v


        AND v.created_at >= #{startDate}


        AND v.created_at <= #{endDate}


        AND v.created_by = #{createdByFilter}



        AND v.park_name = #{communityFilter}


GROUP BY v.violation_type
ORDER BY count DESC

SELECT v.id, v.plate_number as plateNumber, v.violation_type as violationType, v.custom_type as customType, v.location, v.description, v.park_code as parkCode, v.park_name as parkName, v.appointment_time as appointmentTime, v.enter_time as enterTime, v.leave_time as leaveTime, v.status, v.severity, v.photos, v.voice_memo as voiceMemo, v.remark, v.should_blacklist as shouldBlacklist, v.blacklist_reason as blacklistReason, v.blacklist_type_code as blacklistTypeCode, v.blacklist_type_name as blacklistTypeName, v.created_at as createdAt, v.created_by as createdBy, -- 🎓 直接从violations表读取的业主信息（东北林业大学等场景） v.month_ticket_id as monthTicketId, v.is_monthly_ticket as isMonthlyTicket, v.vip_type_name as violationsVipTypeName, v.owner_name as violationsOwnerName, v.owner_phone as violationsOwnerPhone, v.owner_address as violationsOwnerAddress, -- 🎫 月票类型名称：优先使用violations表的vip_type_name，若为空则使用month_tick表的ticket_name COALESCE(NULLIF(v.vip_type_name, ''), mt.ticket_name) as vipTypeName, -- 🔧 预约车辆的业主信息（保留原始字段） a.ownername as appointmentOwnerName, a.ownerphone as appointmentOwnerPhone, -- 🔧 合并后的业主信息：预约车优先用appointment，月票车优先用violations，最后用month_tick COALESCE(NULLIF(a.ownername, ''), NULLIF(v.owner_name, ''), mt.user_name) as ownerName, COALESCE(NULLIF(a.ownerphone, ''), NULLIF(v.owner_phone, ''), mt.user_phone) as ownerPhone, COALESCE(NULLIF(v.owner_address, ''), CONCAT(mt.park_name, '停车场月票车主')) as ownerAddress, v.owner_category as ownerCategory, v.customer_company as customerCompany, v.customer_room_number as customerRoomNumber, -- 🎫 从month_tick表关联获取的月票信息（新增字段，用于前端显示完整月票信息） mt.ticket_name as monthTicketName, mt.user_name as monthTicketUserName, mt.user_phone as monthTicketUserPhone, mt.park_name as monthTicketParkName, -- 🔧 业主类型标识（根据is_monthly_ticket字段判断） CASE WHEN v.is_monthly_ticket = 1 THEN 'monthly' WHEN v.owner_category = '业主' THEN 'local' ELSE 'visitor' END as ownerType, -- 🆕 处理状态相关字段 v.process_status as processStatus, v.process_type as processType, v.processed_at as processedAt, v.processed_by as processedBy, v.process_remark as processRemark, CASE WHEN LENGTH(v.plate_number) = 8 THEN true ELSE false END as isNewEnergy FROM violations v LEFT JOIN month_tick mt ON v.month_ticket_id = mt.id LEFT JOIN appointment a ON v.appointment_id = a.id
AND v.plate_number LIKE CONCAT('%', #{plateNumber}, '%')
AND v.status = #{status}
AND v.violation_type = #{violationType}
AND v.created_at >= #{startDate}
AND v.created_at <= #{endDate}
AND v.created_by = #{createdByFilter}
AND v.park_name = #{communityFilter}
AND v.process_status = #{processStatus}
AND v.process_type = #{processType}
AND (v.process_status IS NULL OR v.process_status = 'pending')
ORDER BY v.created_at DESC
